#!/usr/bin/env -S node --import tsx
// scripts/zodiac-overnight.ts
//
// Continuous Z408 homophonic-substitution attack. Runs forever (or until
// interrupted), each round spawning N random-restart hill-climbs via the
// FRF substrate; persists the best-ever mapping + plaintext to disk after
// every round; logs one progress line per round to stdout.
//
// Designed to run overnight in the background:
//
//   # Launch:
//   cd open-source/gnosis/distributed-inference-host
//   nohup pnpm exec tsx scripts/zodiac-overnight.ts \
//     > /tmp/zodiac.log 2>&1 &
//   echo $! > /tmp/zodiac.pid
//
//   # Monitor:
//   tail -f /tmp/zodiac.log
//   cat /tmp/zodiac-best.json   # current best mapping + plaintext
//
//   # Stop:
//   kill $(cat /tmp/zodiac.pid)
//
// Each round takes ~5-30 seconds depending on FORKS_PER_ROUND and
// MAX_SWAPS_PER_FORK. A 12-hour run gives ~3,000-9,000 rounds = many
// thousand random restarts — enough that the global optimum becomes
// statistically reachable for Z408 (Hardens did it by hand in a week).
//
// SIGINT (Ctrl-C) + SIGTERM are caught; the run flushes its current best
// to disk before exiting so nothing is lost on shutdown.

import { writeFileSync, existsSync, readFileSync, mkdirSync } from 'node:fs';
import { dirname } from 'node:path';
import { argv, exit, hrtime } from 'node:process';

import {
  Z408_CIPHERTEXT,
  Z408_KNOWN_PLAINTEXT,
  ZODIAC_NOTES,
} from '../src/zodiac-fixtures';
import { solveHomophonicSubstitution } from '../src/homophonic-substitution-solver';
import { solveMemeticHomophonic, solveMemeticHomophonicParallel } from '../src/memetic-cipher-solver';
import os from 'node:os';
import { quadgramScore } from '../src/english-frequency';

// ---------------------------------------------------------------------------
// Tunables — bump these higher if you have CPU to burn.
// ---------------------------------------------------------------------------

// Default strategy is 'memetic' — the production-grade approach combining
// GA (population + crossover) with SA (local search) and chaos-driven
// mutation. AZdecrypt-class. Override via --strategy flag.
const FORKS_PER_ROUND = 16;          // SA only: parallel restarts per round
const MAX_SWAPS_PER_FORK = 200_000;  // SA only: bumped 4x for the longer cooling
const STAGNATION_LIMIT = 2_000;      // hill-climb only: stagnation cap
const SEED_BASE = 0xC0DE_0408;       // deterministic seed offset; bumped per round
// Production-tuned SA: T_start=50 lets early SA accept large worsening
// moves freely (escapes the homophone-group plateau quickly when paired
// with the new reassignment proposal); cool=0.99999 means ~1.6M iterations
// to reach T_end (was 0.9999 = 62k iterations — 25× longer search now).
const SA_T_START = 50.0;
const SA_T_END = 0.01;
const SA_COOLING = 0.99999;
// Memetic-only tunables. Production-tuned values:
// - population 64: better basin coverage; the GA's crossover has more
//   diverse genomes to combine.
// - generations 60: lets the population converge then re-diversify
//   (the chaos-driven mutation rate cycles every ~30 gens).
// - sa-swaps 20k: each individual gets a real local search before
//   ranking. This is THE big change vs the overnight run that plateaued.
const MEMETIC_POPULATION = 64;
const MEMETIC_GENERATIONS = 60;
const MEMETIC_SA_SWAPS = 20_000;
const MEMETIC_MUTATION_BASE = 0.12;  // slight bump from 0.10
const MEMETIC_LOGISTIC_R = 3.99;

// ---------------------------------------------------------------------------
// CLI args (lightweight — no parser dep).
// ---------------------------------------------------------------------------

const args = argv.slice(2);
const outPath = arg('--out') ?? '/tmp/zodiac-best.json';
const logEvery = Number(arg('--log-every') ?? '1');
const maxRounds = Number(arg('--max-rounds') ?? Number.MAX_SAFE_INTEGER);
const cipherArg = arg('--cipher') ?? 'z408';
const strategyArg = arg('--strategy') ?? 'memetic';
type Strategy = 'hill-climb' | 'simulated-annealing' | 'memetic';
const STRATEGY = strategyArg as Strategy;
if (!['hill-climb', 'simulated-annealing', 'memetic'].includes(STRATEGY)) {
  console.error(`Unknown --strategy: ${strategyArg}. Supported: hill-climb | simulated-annealing | memetic`);
  exit(1);
}

function arg(name: string): string | undefined {
  const i = args.indexOf(name);
  if (i === -1 || i + 1 >= args.length) return undefined;
  return args[i + 1];
}

// Cipher selector. For now Z408 only; the script is structured so adding
// other homophonic ciphers is a one-line case below.
let CIPHERTEXT: string;
let CIPHER_LABEL: string;
let KNOWN_PLAINTEXT: string | undefined;
switch (cipherArg) {
  case 'z408':
    CIPHERTEXT = Z408_CIPHERTEXT;
    CIPHER_LABEL = 'Z408';
    KNOWN_PLAINTEXT = Z408_KNOWN_PLAINTEXT;
    break;
  default:
    console.error(`Unknown --cipher: ${cipherArg}. Supported: z408`);
    exit(1);
}

// ---------------------------------------------------------------------------
// State.
// ---------------------------------------------------------------------------

interface BestRecord {
  cipher: string;
  status: string;
  cipherLength: number;
  symbolsCount: number;
  bestScore: number;
  bestPlaintext: string;
  bestMapping: Record<string, string>;
  bestRound: number;
  totalRounds: number;
  totalForks: number;
  knownPlaintextAccuracy?: number;
  startedAt: string;
  updatedAt: string;
  elapsedSec: number;
}

let bestScore = -Infinity;
let bestPlaintext = '';
let bestMapping: ReadonlyMap<string, string> = new Map();
let bestRound = 0;
let totalRounds = 0;
let totalForks = 0;
let symbolsCount = 0;
const startedAt = new Date().toISOString();
const t0 = hrtime.bigint();

// Resume from disk if a prior run exists.
if (existsSync(outPath)) {
  try {
    const prior = JSON.parse(readFileSync(outPath, 'utf8')) as BestRecord;
    if (prior.cipher === CIPHER_LABEL) {
      bestScore = prior.bestScore;
      bestPlaintext = prior.bestPlaintext;
      bestMapping = new Map(Object.entries(prior.bestMapping));
      bestRound = prior.bestRound;
      console.log(
        `[resume] loaded prior best from ${outPath}: score=${bestScore.toFixed(3)}, ` +
        `round=${bestRound}, plaintext starts with "${bestPlaintext.slice(0, 60)}..."`,
      );
    }
  } catch (err) {
    console.warn(`[resume] could not read ${outPath}: ${(err as Error).message}`);
  }
}

// ---------------------------------------------------------------------------
// Persistence.
// ---------------------------------------------------------------------------

function persist(): void {
  const elapsedSec = Number(hrtime.bigint() - t0) / 1e9;
  const record: BestRecord = {
    cipher: CIPHER_LABEL,
    status: ZODIAC_NOTES.z408.status,
    cipherLength: CIPHERTEXT.length,
    symbolsCount,
    bestScore,
    bestPlaintext,
    bestMapping: Object.fromEntries(bestMapping),
    bestRound,
    totalRounds,
    totalForks,
    knownPlaintextAccuracy: KNOWN_PLAINTEXT
      ? characterAccuracy(bestPlaintext.replace(/[^A-Z]/g, ''), KNOWN_PLAINTEXT)
      : undefined,
    startedAt,
    updatedAt: new Date().toISOString(),
    elapsedSec,
  };
  mkdirSync(dirname(outPath), { recursive: true });
  writeFileSync(outPath, JSON.stringify(record, null, 2));
}

function characterAccuracy(a: string, b: string): number {
  const minLen = Math.min(a.length, b.length);
  if (minLen === 0) return 0;
  let match = 0;
  for (let i = 0; i < minLen; i++) if (a[i] === b[i]) match++;
  return match / minLen;
}

// ---------------------------------------------------------------------------
// Graceful shutdown.
// ---------------------------------------------------------------------------

let shuttingDown = false;
function shutdown(signal: string): void {
  if (shuttingDown) return;
  shuttingDown = true;
  console.log(`\n[${signal}] flushing best-ever result to ${outPath}...`);
  persist();
  console.log(
    `[${signal}] done. bestScore=${bestScore.toFixed(3)}, ` +
    `bestRound=${bestRound}/${totalRounds}, totalForks=${totalForks}`,
  );
  exit(0);
}
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('SIGTERM', () => shutdown('SIGTERM'));

// ---------------------------------------------------------------------------
// Main loop.
// ---------------------------------------------------------------------------

console.log(
  `[overnight] cipher=${CIPHER_LABEL} length=${CIPHERTEXT.length} ` +
  `forks/round=${FORKS_PER_ROUND} max-swaps/fork=${MAX_SWAPS_PER_FORK} ` +
  `out=${outPath} startedAt=${startedAt}`,
);
console.log(
  `[overnight] ${CIPHER_LABEL} status: ${ZODIAC_NOTES.z408.status} by ` +
  `${ZODIAC_NOTES.z408.solver} (${ZODIAC_NOTES.z408.year})`,
);

while (totalRounds < maxRounds && !shuttingDown) {
  totalRounds++;
  const seed = SEED_BASE + totalRounds * 17;

  let result: {
    plaintext: string;
    mapping: ReadonlyMap<string, string>;
    score: number;
    candidates: ReadonlyArray<unknown>;
    symbols: ReadonlyArray<string>;
  };
  if (STRATEGY === 'memetic') {
    // Sequential by default. solveMemeticHomophonicParallel exists and
    // works structurally, but tsx + worker_threads has a known module-
    // graph isolation issue (workers can't propagate the TS loader to
    // their own imports). Use the parallel path only with a built JS
    // bundle. Pass --parallel to opt in regardless (will fail without
    // a JS build step in the worker's module graph).
    const useParallel = args.includes('--parallel');
    const m = useParallel
      ? await solveMemeticHomophonicParallel({
          ciphertext: CIPHERTEXT,
          populationSize: MEMETIC_POPULATION,
          generations: MEMETIC_GENERATIONS,
          saSwapsPerIndividual: MEMETIC_SA_SWAPS,
          saTemperatureStart: SA_T_START,
          saTemperatureEnd: SA_T_END,
          saCoolingRate: SA_COOLING,
          mutationRateBase: MEMETIC_MUTATION_BASE,
          logisticR: MEMETIC_LOGISTIC_R,
          seed,
          parallel: { workers: Number(arg('--workers') ?? Math.max(1, Math.floor(os.cpus().length / 2))) },
        })
      : solveMemeticHomophonic({
          ciphertext: CIPHERTEXT,
          populationSize: MEMETIC_POPULATION,
          generations: MEMETIC_GENERATIONS,
          saSwapsPerIndividual: MEMETIC_SA_SWAPS,
          saTemperatureStart: SA_T_START,
          saTemperatureEnd: SA_T_END,
          saCoolingRate: SA_COOLING,
          mutationRateBase: MEMETIC_MUTATION_BASE,
          logisticR: MEMETIC_LOGISTIC_R,
          seed,
        });
    result = {
      plaintext: m.plaintext,
      mapping: m.mapping,
      score: m.score,
      candidates: new Array(MEMETIC_POPULATION),
      symbols: m.symbols,
    };
    totalForks += MEMETIC_POPULATION * MEMETIC_GENERATIONS;
  } else {
    result = solveHomophonicSubstitution({
      ciphertext: CIPHERTEXT,
      forks: FORKS_PER_ROUND,
      maxSwapsPerFork: MAX_SWAPS_PER_FORK,
      stagnationLimit: STAGNATION_LIMIT,
      seed,
      strategy: STRATEGY,
      annealing: {
        temperatureStart: SA_T_START,
        temperatureEnd: SA_T_END,
        coolingRate: SA_COOLING,
      },
    });
    totalForks += result.candidates.length;
  }
  symbolsCount = result.symbols.length;

  const improved = result.score > bestScore;
  if (improved) {
    bestScore = result.score;
    bestPlaintext = result.plaintext;
    bestMapping = result.mapping;
    bestRound = totalRounds;
    persist();
  }

  if (totalRounds % logEvery === 0 || improved) {
    const elapsedSec = Number(hrtime.bigint() - t0) / 1e9;
    const acc = KNOWN_PLAINTEXT
      ? characterAccuracy(bestPlaintext.replace(/[^A-Z]/g, ''), KNOWN_PLAINTEXT)
      : 0;
    const flag = improved ? '*' : ' ';
    console.log(
      `[r=${totalRounds.toString().padStart(5)}${flag}] ` +
      `roundScore=${result.score.toFixed(3)} ` +
      `bestScore=${bestScore.toFixed(3)} (round ${bestRound}) ` +
      `forks=${totalForks} ` +
      `acc=${(acc * 100).toFixed(1)}% ` +
      `t=${elapsedSec.toFixed(0)}s ` +
      `head="${bestPlaintext.replace(/\s+/g, '').slice(0, 40)}"`,
    );
  }
}

shutdown('done');
